extra.modelCss:
/* Kit mínimo de acessibilidade (CSS) */

:root {
  --accent: #60a5fa;
  --danger: #ef4444;
}

/* Foco visível e bonito */
:focus-visible {
  outline: 3px solid var(--accent);
  outline-offset: 3px;
}

/* Hover e foco com o mesmo feedback */
.link:hover,
.link:focus-visible {
  text-decoration: underline;
}

/* Botão com alvo confortável */
.btn {
  padding: 10px 14px;
  border-radius: 12px;
}

.icon-btn {
  width: 44px;
  height: 44px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

/* Estado de erro */
.input-error {
  border-color: var(--danger);
}

/* Respeitar redução de movimento */
@media (prefers-reduced-motion: reduce) {
  * {
    animation: none !important;
    transition: none !important;
    scroll-behavior: auto !important;
  }
}
